use actix_web::{web, HttpResponse, HttpRequest};
use serde::{Deserialize, Serialize};
use sqlx::PgPool;

#[derive(Serialize)]
struct InvoiceDetails {
    id: i32,
    invoice_number: String,
    customer_name: String,
    amount: f64,
    status: String,
    created_at: chrono::NaiveDateTime,
}

#[derive(Clone)]
struct AuthenticatedUser {
    id: i32,
    email: String,
}

async fn get_invoice_by_id(
    req: HttpRequest,
    pool: web::Data<PgPool>,
    invoice_id: web::Path<i32>,
) -> HttpResponse {
    let user = match req.extensions().get::<AuthenticatedUser>() {
        Some(user) => user.clone(),
        None => return HttpResponse::Unauthorized().json("User not authenticated"),
    };

    let invoice_id = invoice_id.into_inner();

    let invoice = sqlx::query_as!(
        InvoiceDetails,
        r#"
        SELECT id, invoice_number, customer_name, amount, status, created_at
        FROM invoices
        WHERE id = $1 AND user_id = $2
        "#,
        invoice_id,
        user.id
    )
    .fetch_optional(pool.get_ref())
    .await;

    match invoice {
        Ok(Some(invoice)) => HttpResponse::Ok().json(invoice),
        Ok(None) => HttpResponse::NotFound().json("Invoice not found"),
        Err(e) => HttpResponse::InternalServerError().json(format!("Database error: {}", e)),
    }
}